!container ||
container._aplayer
)

return;






fetch("https://api.injahow.cn/meting/?server=netease&type=playlist&id=18138558663&r=1784839186048")

.then(response=>{


if(
!response.ok
){

throw new Error(
"Music API request failed"
);

}



return response.text();



})


.then(text=>{



let data;



try{


data =
JSON.parse(text);



}catch(e){



console.error(
"Music API did not return JSON:",
text
);


return;


}





if(
!data ||
!data.length
)

return;






const ap =
new APlayer({

container,




    autoplay:false,

    theme:'#7cb85c',

    loop:'all',

    order:'list',

    volume:0.7,

    lrcType:0

  ,


audio:data


});







container._aplayer=ap;



window.articleAPlayers.push(ap);








ap.on(
"play",
()=>{



if(
window.globalAPlayer &&
window.globalAPlayer!==ap
){

window.globalAPlayer.pause();

}





window.articleAPlayers
.forEach(player=>{


if(player!==ap){

player.pause();


}


});



}

);




});



};






